'use client';

/**
 * Página principal do Dashboard
 */

import { useState } from 'react';
import { useUserProfile } from '@/hooks/useUserProfile';
import { useDashboardMetrics } from '@/hooks/useDashboardMetrics';
import VisionDashboard from '@/components/dashboard/VisionDashboard';
import { Skeleton } from '@/components/ui/skeleton';

export default function DashboardPage() {
    const { isSecretaria, isLoading: isLoadingProfile } = useUserProfile();
    const { isLoading: isLoadingMetrics, error } = useDashboardMetrics();
    const [viewMode, setViewMode] = useState<'vision' | 'detailed'>('vision');

    if (isLoadingProfile || isLoadingMetrics) {
        return (
            <div className="min-h-screen space-y-5 bg-background font-sans px-3 sm:px-4 lg:px-6 pb-10 pt-6">
                <div className="space-y-4">
                    <Skeleton className="h-10 w-64" />
                    <Skeleton className="h-6 w-48" />
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                    {[1, 2, 3].map((i) => (
                        <Skeleton key={i} className="h-40 w-full rounded-xl" />
                    ))}
                </div>
                <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                    <Skeleton className="lg:col-span-2 h-80 rounded-xl" />
                    <Skeleton className="h-80 rounded-xl" />
                </div>
            </div>
        );
    }

    if (error) {
        return (
            <div className="min-h-screen flex items-center justify-center bg-background text-foreground">
                <div className="text-center text-destructive">
                    Erro ao carregar métricas: {(error as Error).message}
                </div>
            </div>
        );
    }

    // Main Dashboard - VisionDashboard handles role-based views internally
    return (
        <VisionDashboard
            viewMode={viewMode}
            onViewModeChange={setViewMode}
        />
    );
}
