'use client';

/**
 * Dashboard principal com visão geral da clínica
 */

import { VisionHeroMetrics } from './vision/VisionHeroMetrics';
import { VisionCard } from './vision/VisionCard';
import { useUserProfile } from '@/hooks/useUserProfile';
import { useDashboardMetrics } from '@/hooks/useDashboardMetrics';
import { Skeleton } from '@/components/ui/skeleton';
import { Button } from '@/components/ui/button';
import { Calendar as CalendarIcon, Filter, Search, Users, Target, TrendingUp } from 'lucide-react';
import { Input } from '@/components/ui/input';
import { formatCurrency } from '@/lib/currency';
import { useRouter } from 'next/navigation';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';

interface ViewModeProps {
    viewMode?: 'vision' | 'detailed';
    onViewModeChange?: (mode: 'vision' | 'detailed') => void;
}

export default function VisionDashboard({ viewMode, onViewModeChange }: ViewModeProps) {
    const { profile, isVendedor } = useUserProfile();
    const { data: dashboardMetrics } = useDashboardMetrics();
    const router = useRouter();

    if (!profile) {
        return <div className="p-8"><Skeleton className="h-96 w-full" /></div>;
    }

    return (
        <div className="min-h-screen bg-background text-foreground p-4 md:p-8 space-y-8 font-sans transition-colors duration-300">

            {/* Header Section */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight text-foreground">
                        Olá, <span className="text-primary">{profile.full_name?.split(' ')[0] || 'Bem-vindo'}</span>
                    </h1>
                    <p className="text-muted-foreground mt-1 font-light tracking-wide">
                        Aqui está o relatório geral da sua clínica hoje.
                    </p>
                </div>

                <div className="flex items-center gap-3">
                    <div className="relative hidden md:block">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Buscar..."
                            className="pl-9 bg-card border-border text-foreground placeholder:text-muted-foreground w-64 focus-visible:ring-primary rounded-xl transition-all hover:bg-muted/50"
                        />
                    </div>
                    {/* View Toggle */}
                    {onViewModeChange && (
                        <div className="flex items-center gap-1 bg-muted/20 p-1 rounded-xl border border-border/50">
                            <Button
                                variant={viewMode === 'vision' ? 'default' : 'ghost'}
                                size="sm"
                                onClick={() => onViewModeChange('vision')}
                                className={`text-xs h-8 px-3 rounded-lg ${viewMode === 'vision' ? 'shadow-sm' : 'text-muted-foreground hover:text-foreground'}`}
                            >
                                Visão Geral
                            </Button>
                            <Button
                                variant={viewMode === 'detailed' ? 'default' : 'ghost'}
                                size="sm"
                                onClick={() => onViewModeChange('detailed')}
                                className={`text-xs h-8 px-3 rounded-lg ${viewMode === 'detailed' ? 'shadow-sm' : 'text-muted-foreground hover:text-foreground'}`}
                            >
                                Detalhada
                            </Button>
                        </div>
                    )}
                    <Button variant="outline" size="icon" className="bg-card border-border text-foreground hover:bg-muted/50 rounded-xl">
                        <Filter className="h-4 w-4" />
                    </Button>
                    <Button
                        className="bg-primary hover:bg-primary/90 text-primary-foreground shadow-lg shadow-primary/20 border-0 rounded-xl"
                        onClick={() => router.push('/agenda')}
                    >
                        <CalendarIcon className="h-4 w-4 mr-2" />
                        Agendar
                    </Button>
                </div>
            </div>

            {/* Metrics Grid */}
            <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 delay-100">
                <VisionHeroMetrics />
            </div>

            {/* Main Content Grid */}
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 animate-in fade-in slide-in-from-bottom-6 duration-700 delay-200">

                {/* Left Column - Charts & Analysis */}
                <div className="lg:col-span-2 space-y-6">
                    {isVendedor ? (
                        // Vendedor View
                        <>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                <VisionCard title="Pipeline de Vendas" className="h-full">
                                    <PipelineFunnelPreview
                                        dealsByStage={dashboardMetrics?.dealsByStage || {}}
                                    />
                                </VisionCard>

                                <VisionCard title="Acesso Rápido" className="h-full">
                                    <div className="grid grid-cols-2 gap-3 h-full items-center">
                                        <Button
                                            variant="outline"
                                            className="h-full py-4 flex flex-col items-center justify-center gap-2 border-border/50 hover:border-primary/50 hover:bg-primary/5 text-muted-foreground hover:text-primary transition-all"
                                            onClick={() => router.push('/crm')}
                                        >
                                            <Users className="h-6 w-6 text-primary" />
                                            CRM
                                        </Button>
                                        <Button
                                            variant="outline"
                                            className="h-full py-4 flex flex-col items-center justify-center gap-2 border-border/50 hover:border-orange-500/50 hover:bg-orange-500/5 text-muted-foreground hover:text-orange-500 transition-all"
                                        >
                                            <Target className="h-6 w-6 text-orange-500" />
                                            Tarefas
                                        </Button>
                                    </div>
                                </VisionCard>
                            </div>

                            <VisionCard title="Performance Mensal">
                                <MonthlyRevenuePreview
                                    monthlyRevenue={dashboardMetrics?.monthlyRevenue || []}
                                />
                            </VisionCard>
                        </>
                    ) : (
                        // Admin View
                        <>
                            <VisionCard title="Fluxo de Caixa Real" action={
                                <div className="flex bg-muted/50 rounded-lg p-0.5">
                                    <Button variant="ghost" size="sm" className="h-7 text-xs rounded-md bg-card shadow-sm text-foreground">Fluxo</Button>
                                    <Button variant="ghost" size="sm" className="h-7 text-xs rounded-md text-muted-foreground hover:text-foreground">Saldo</Button>
                                </div>
                            }>
                                <FinancialFlowPreview
                                    monthlyFinancials={dashboardMetrics?.monthlyFinancials || []}
                                />
                            </VisionCard>

                            <VisionCard title="Previsão de Receita (CRM)">
                                <MonthlyRevenuePreview
                                    monthlyRevenue={dashboardMetrics?.monthlyRevenue || []}
                                />
                            </VisionCard>

                            <VisionCard title="Deals por Estágio">
                                <PipelineFunnelPreview
                                    dealsByStage={dashboardMetrics?.dealsByStage || {}}
                                />
                            </VisionCard>
                        </>
                    )}
                </div>

                {/* Right Column - Recent Activity */}
                <div className="space-y-6">
                    <VisionCard title="Deals Recentes">
                        <RecentDealsPreview
                            recentDeals={dashboardMetrics?.recentDeals || []}
                        />
                    </VisionCard>

                    <VisionCard title="Métricas de Conversão">
                        <ConversionPreview
                            conversionByStage={dashboardMetrics?.conversionByStage || []}
                        />
                    </VisionCard>
                </div>

            </div>
        </div>
    );
}

// Sub-components for dashboard sections

function PipelineFunnelPreview({ dealsByStage }: { dealsByStage: Record<string, { count: number; value: number }> }) {
    const stages = [
        { key: 'lead_novo', label: 'Leads Novos', color: 'bg-blue-500' },
        { key: 'qualificado', label: 'Qualificados', color: 'bg-purple-500' },
        { key: 'apresentacao', label: 'Apresentação', color: 'bg-cyan-500' },
        { key: 'proposta', label: 'Proposta', color: 'bg-orange-500' },
        { key: 'negociacao', label: 'Negociação', color: 'bg-amber-500' },
        { key: 'fechado_ganho', label: 'Ganhos', color: 'bg-emerald-500' },
    ];

    const maxCount = Math.max(...stages.map(s => dealsByStage[s.key]?.count || 0), 1);

    return (
        <div className="space-y-3">
            {stages.map(stage => {
                const data = dealsByStage[stage.key] || { count: 0, value: 0 };
                const width = (data.count / maxCount) * 100;

                return (
                    <div key={stage.key} className="space-y-1">
                        <div className="flex justify-between text-sm">
                            <span className="text-muted-foreground">{stage.label}</span>
                            <span className="font-medium">{data.count}</span>
                        </div>
                        <div className="h-2 bg-muted rounded-full overflow-hidden">
                            <div
                                className={`h-full ${stage.color} rounded-full transition-all duration-500`}
                                style={{ width: `${width}%` }}
                            />
                        </div>
                    </div>
                );
            })}
        </div>
    );
}

function MonthlyRevenuePreview({ monthlyRevenue }: { monthlyRevenue: Array<{ month: string; projected: number; closed: number }> }) {
    const lastSixMonths = monthlyRevenue.slice(-6);
    const maxValue = Math.max(...lastSixMonths.flatMap(m => [m.projected, m.closed]), 1);

    return (
        <div className="space-y-4">
            <div className="flex items-center gap-4 text-xs text-muted-foreground">
                <div className="flex items-center gap-1">
                    <div className="w-3 h-3 bg-primary rounded" />
                    Projetado
                </div>
                <div className="flex items-center gap-1">
                    <div className="w-3 h-3 bg-emerald-500 rounded" />
                    Fechado
                </div>
            </div>
            <div className="flex items-end justify-between gap-2 h-32">
                {lastSixMonths.map((month, idx) => (
                    <div key={idx} className="flex-1 flex flex-col items-center gap-1">
                        <div className="w-full flex gap-1 items-end h-24">
                            <div
                                className="flex-1 bg-primary/30 rounded-t"
                                style={{ height: `${(month.projected / maxValue) * 100}%` }}
                            />
                            <div
                                className="flex-1 bg-emerald-500 rounded-t"
                                style={{ height: `${(month.closed / maxValue) * 100}%` }}
                            />
                        </div>
                        <span className="text-xs text-muted-foreground capitalize">{month.month}</span>
                    </div>
                ))}
            </div>
        </div>
    );
}

function RecentDealsPreview({ recentDeals }: { recentDeals: Array<{ id: string; title: string; value: number; stage: string; contact?: { full_name?: string } }> }) {
    if (recentDeals.length === 0) {
        return (
            <p className="text-muted-foreground text-sm text-center py-8">
                Nenhum deal recente
            </p>
        );
    }

    return (
        <div className="space-y-3">
            {recentDeals.slice(0, 5).map(deal => (
                <div key={deal.id} className="flex items-center justify-between p-3 bg-muted/30 rounded-lg">
                    <div>
                        <p className="font-medium text-sm">{deal.title || deal.contact?.full_name || 'Sem título'}</p>
                        <p className="text-xs text-muted-foreground capitalize">{deal.stage?.replace('_', ' ')}</p>
                    </div>
                    <span className="text-sm font-medium text-primary">
                        {formatCurrency(deal.value || 0)}
                    </span>
                </div>
            ))}
        </div>
    );
}

function ConversionPreview({ conversionByStage }: { conversionByStage: Array<{ stage: string; conversion: number }> }) {
    const stageLabels: Record<string, string> = {
        'lead_novo': 'Lead → Qualificado',
        'qualificado': 'Qualificado → Apresentação',
        'apresentacao': 'Apresentação → Proposta',
        'proposta': 'Proposta → Negociação',
        'negociacao': 'Negociação → Fechado',
    };

    if (conversionByStage.length === 0) {
        return (
            <p className="text-muted-foreground text-sm text-center py-8">
                Sem dados de conversão
            </p>
        );
    }

    return (
        <div className="space-y-3">
            {conversionByStage.map(item => (
                <div key={item.stage} className="flex items-center justify-between">
                    <span className="text-sm text-muted-foreground">{stageLabels[item.stage] || item.stage}</span>
                    <div className="flex items-center gap-2">
                        <div className="w-16 h-2 bg-muted rounded-full overflow-hidden">
                            <div
                                className="h-full bg-primary rounded-full"
                                style={{ width: `${Math.min(item.conversion, 100)}%` }}
                            />
                        </div>
                        <span className="text-sm font-medium w-12 text-right">{item.conversion.toFixed(0)}%</span>
                    </div>
                </div>
            ))}
        </div>
    );
}

function FinancialFlowPreview({ monthlyFinancials }: { monthlyFinancials: Array<{ month: string; revenue: number; expenses: number; balance: number }> }) {
    const lastSixMonths = monthlyFinancials.slice(-6);
    const maxValue = Math.max(...lastSixMonths.flatMap(m => [m.revenue, m.expenses]), 1);

    return (
        <div className="space-y-4">
            <div className="flex items-center gap-4 text-xs text-muted-foreground">
                <div className="flex items-center gap-1">
                    <div className="w-3 h-3 bg-emerald-500 rounded" />
                    Receitas
                </div>
                <div className="flex items-center gap-1">
                    <div className="w-3 h-3 bg-rose-500 rounded" />
                    Despesas
                </div>
                <div className="flex items-center gap-1">
                    <div className="w-3 h-1 bg-cyan-500 rounded-full" />
                    Saldo
                </div>
            </div>
            <div className="flex items-end justify-between gap-2 h-32">
                {lastSixMonths.map((month, idx) => (
                    <div key={idx} className="flex-1 flex flex-col items-center gap-1 group relative">
                        {/* Tooltip placeholder */}
                        <div className="absolute bottom-full mb-2 hidden group-hover:block bg-popover text-popover-foreground text-[10px] p-2 rounded shadow-lg z-10 whitespace-nowrap border border-border">
                            <p className="text-emerald-500">Rec: {formatCurrency(month.revenue)}</p>
                            <p className="text-rose-500">Desp: {formatCurrency(month.expenses)}</p>
                            <p className="text-cyan-500 font-bold border-t border-border/50 mt-1 pt-1">
                                Saldo: {formatCurrency(month.balance)}
                            </p>
                        </div>

                        <div className="w-full flex gap-1 items-end h-24 relative">
                            {/* Revenue Bar */}
                            <div
                                className="flex-1 bg-emerald-500 rounded-t hover:bg-emerald-400 transition-colors"
                                style={{ height: `${(month.revenue / maxValue) * 100}%` }}
                            />
                            {/* Expense Bar */}
                            <div
                                className="flex-1 bg-rose-500 rounded-t hover:bg-rose-400 transition-colors"
                                style={{ height: `${(month.expenses / maxValue) * 100}%` }}
                            />
                        </div>
                        <span className="text-xs text-muted-foreground capitalize">{month.month}</span>
                    </div>
                ))}
            </div>
        </div>
    );
}
